import{_ as d,o as r,c as a,a3 as e}from"./chunks/framework.CVjg771q.js";const p=JSON.parse('{"title":"十二生肖","description":"子鼠丑牛寅虎卯兔——地支的民俗化表达，每个人出生那年都带着一个动物的印记。","frontmatter":{"pageClass":"dao-changshi-page","aside":false,"title":"十二生肖","description":"子鼠丑牛寅虎卯兔——地支的民俗化表达，每个人出生那年都带着一个动物的印记。"},"headers":[],"relativePath":"changshi/shengxiao/index.md","filePath":"changshi/shengxiao/index.md","lastUpdated":1779783531000}'),o={name:"changshi/shengxiao/index.md"};function h(i,t,n,l,s,c){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="十二生肖" tabindex="-1">十二生肖 <a class="header-anchor" href="#十二生肖" aria-label="Permalink to &quot;十二生肖&quot;">​</a></h1><blockquote><p>鼠、牛、虎、兔、龙、蛇、马、羊、猴、鸡、狗、猪——十二年一轮，周而复始。 生肖不是迷信，是地支的民俗界面，是中国人记录岁月的一种古老方式。</p></blockquote><h2 id="生肖与地支" tabindex="-1">生肖与地支 <a class="header-anchor" href="#生肖与地支" aria-label="Permalink to &quot;生肖与地支&quot;">​</a></h2><table tabindex="0"><thead><tr><th>地支</th><th>生肖</th><th>时辰</th><th>现代时间</th></tr></thead><tbody><tr><td>子</td><td>鼠</td><td>子时</td><td>23:00–01:00</td></tr><tr><td>丑</td><td>牛</td><td>丑时</td><td>01:00–03:00</td></tr><tr><td>寅</td><td>虎</td><td>寅时</td><td>03:00–05:00</td></tr><tr><td>卯</td><td>兔</td><td>卯时</td><td>05:00–07:00</td></tr><tr><td>辰</td><td>龙</td><td>辰时</td><td>07:00–09:00</td></tr><tr><td>巳</td><td>蛇</td><td>巳时</td><td>09:00–11:00</td></tr><tr><td>午</td><td>马</td><td>午时</td><td>11:00–13:00</td></tr><tr><td>未</td><td>羊</td><td>未时</td><td>13:00–15:00</td></tr><tr><td>申</td><td>猴</td><td>申时</td><td>15:00–17:00</td></tr><tr><td>酉</td><td>鸡</td><td>酉时</td><td>17:00–19:00</td></tr><tr><td>戌</td><td>狗</td><td>戌时</td><td>19:00–21:00</td></tr><tr><td>亥</td><td>猪</td><td>亥时</td><td>21:00–23:00</td></tr></tbody></table><h2 id="起源考证" tabindex="-1">起源考证 <a class="header-anchor" href="#起源考证" aria-label="Permalink to &quot;起源考证&quot;">​</a></h2><blockquote><p>参考：知乎 <a href="https://www.zhihu.com/question/20574079/answer/485200160" target="_blank" rel="noreferrer">苏漢原</a></p></blockquote><p>十二生肖的来历众说纷纭。一个最可能接近真相的解释是：<strong>生肖来源于地支，但并非与地支同时产生</strong>——它是在地支用于表示十二时辰后，人们根据动物在每个时辰的相对活跃时间，以及地支最初的字体构形，两者相互附会而产生的。</p><h3 id="从「亥」到「豕」-字形的证据" tabindex="-1">从「亥」到「豕」：字形的证据 <a class="header-anchor" href="#从「亥」到「豕」-字形的证据" aria-label="Permalink to &quot;从「亥」到「豕」：字形的证据&quot;">​</a></h3><p>地支「亥」的古文字形演变是关键的突破口。甲骨文的「亥」笔画简洁，但到了西周晚期，金文「亥」的构形几乎与「豕」（猪）重合——这暗示最晚在西周以前，人们就已用生肖来解读地支。</p><p>先秦的「亥」字，除了用作人名，几乎全部用作地支。字形向「豕」靠拢，说明生肖思想已经被用来附会地支。到了小篆时代，地支字形又大体恢复了甲骨文的构形——这是一次「去生肖化」。</p><h3 id="演变时间线" tabindex="-1">演变时间线 <a class="header-anchor" href="#演变时间线" aria-label="Permalink to &quot;演变时间线&quot;">​</a></h3><ol><li><strong>帝尧时代</strong>：十二地支用于记月，一季三个月，平年十二月</li><li><strong>商代中后期</strong>：地支扩展为记录每天的十二时辰</li><li><strong>商周之际</strong>：普通人用动物来指代时辰，生肖开始与地支结合</li><li><strong>西周早期</strong>：两种地支思想并存（含生肖 / 不含生肖），体现在两种字形并存的青铜铭文中</li><li><strong>后世</strong>：十二生肖固定下来，反过来用于纪年</li></ol><h3 id="各生肖如何附会地支" tabindex="-1">各生肖如何附会地支 <a class="header-anchor" href="#各生肖如何附会地支" aria-label="Permalink to &quot;各生肖如何附会地支&quot;">​</a></h3><table tabindex="0"><thead><tr><th>地支</th><th>生肖</th><th>附会依据</th></tr></thead><tbody><tr><td>子</td><td>鼠</td><td>子息繁衍如鼠之繁盛；子时鼠最活跃</td></tr><tr><td>丑</td><td>牛</td><td>金文「丑」形如有力的手臂，附会牛之力大；丑时牛反刍</td></tr><tr><td>寅</td><td>虎</td><td>金文「寅」构形涉及雄性，虎类中药有壮阳之说</td></tr><tr><td>卯</td><td>兔</td><td>金文「卯」形似兔眼与三瓣唇</td></tr><tr><td>辰</td><td>龙</td><td>辰时多有云，「云从龙」；龙与雷声相关，雷后常雨，农耕所盼</td></tr><tr><td>巳</td><td>蛇</td><td>字形从大头婴儿状变为蛇状线形；巳时蛇晒太阳</td></tr><tr><td>午</td><td>马</td><td>「午」本杵，马奔跑声如杵击</td></tr><tr><td>未</td><td>羊</td><td>「未」为树苗，羊食树叶嫩芽</td></tr><tr><td>申</td><td>猴</td><td>金文「申」形似猴子的简笔画</td></tr><tr><td>酉</td><td>鸡</td><td>酉时黄昏，鸡夜盲，天黑前必回窝——最贴合的时辰对应</td></tr><tr><td>戌</td><td>狗</td><td>戌时入夜，狗对夜间动静最敏感；「戌」本即戌守</td></tr><tr><td>亥</td><td>猪</td><td>亥时人定（就寝），猪睡得最多</td></tr></tbody></table>',14)])])}const g=d(o,[["render",h]]);export{p as __pageData,g as default};
